    set(key, value) {
      if (_incognito) { _memStore.set(key, value); return; }
      if (!available) return;
      try {
        localStorage.setItem(key, value);
      } catch (e) {
        // Propagate quota errors so callers can detect write failures.
        // Swallow SecurityError (storage revoked after initial check).
        if (e instanceof DOMException && e.name === 'SecurityError') return;
        throw e;
      }
    },
    /** Remove a key from storage (no-op when unavailable). */
    remove(key) {
      if (_incognito) { _memStore.delete(key); return; }
      try { if (available) localStorage.removeItem(key); } catch (_) { /* ignore */ }
    },
    /** Number of entries currently stored (0 when unavailable). */
    get length() {
      try { return available ? localStorage.length : 0; } catch (_) { return 0; }
    },
    /** Return the key at a given index, or null when unavailable. */
    key(i) {
      try { return available ? localStorage.key(i) : null; } catch (_) { return null; }
    },
    /** Whether localStorage passed the availability probe. */
    isAvailable() { return available; },
    /**
     * Retrieve and JSON-parse a value.  Returns `fallback` when the key is
     * missing, storage is unavailable, or the stored value is not valid JSON.
     * @param {string} key
     * @param {*} [fallback=null]
     * @returns {*}
     */
    getJSON(key, fallback = null) {
      const raw = this.get(key);
      if (raw == null) return fallback;
      try {
        const parsed = JSON.parse(raw);
        return (parsed !== null && typeof parsed === 'object')
          ? sanitizeStorageObject(parsed)
          : parsed;
      } catch (_) { return fallback; }
    },
    /**
     * JSON-stringify and persist a value.
     * @param {string} key
     * @param {*} value  - must be JSON-serializable
     */
    setJSON(key, value) {
      this.set(key, JSON.stringify(value));
    },
    /**
     * Fire-and-forget version of set that silently swallows all
     * exceptions (quota exceeded, security errors, etc.).
     * @param {string} key
     * @param {string} value
     */
    trySet(key, value) {
      try { this.set(key, value); } catch (_) { /* best-effort persist */ }
    },
    /**
     * Fire-and-forget version of setJSON that silently swallows all
     * exceptions (quota exceeded, security errors, etc.).
     *
     * Replaces the pervasive `try { SafeStorage.setJSON(k, v); } catch {}` pattern
     * found throughout the codebase, making intent explicit and reducing boilerplate.
     *
     * @param {string} key
     * @param {*} value  - must be JSON-serializable
     */
    trySetJSON(key, value) {
      try { this.setJSON(key, value); } catch (_) { /* best-effort persist */ }
    },

