.autopilot-panel{position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);width:540px;max-width:95vw;max-height:85vh;overflow-y:auto;background:var(--bg-card,#1e1e2e);border:1px solid var(--border,#333);border-radius:12px;padding:0;z-index:10002;box-shadow:0 12px 40px rgba(0,0,0,.5)}
