.btn-primary{background:#2196F3;color:#fff;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-size:.95rem;font-weight:600;width:100%;margin-top:8px}
.btn-primary:hover{background:#1976D2}
.autopilot-status{display:flex;align-items:center;gap:10px;margin-bottom:12px;flex-wrap:wrap}
