.context-stats-grid { display: flex; flex-wrap: wrap; gap: 8px; }
.context-stats-grid span { font-size: 0.8rem; color: var(--text-primary, #ddd); background: var(--bg-tertiary, #252525); padding: 4px 8px; border-radius: 4px; }
.context-entity-group { margin-bottom: 8px; }
.context-entity-group small { color: var(--text-secondary, #888); font-size: 0.75rem; display: block; margin-bottom: 4px; }
.context-entity-tag { display: inline-block; font-size: 0.75rem; padding: 2px 8px; border-radius: 12px; margin: 2px 4px 2px 0; max-width: 100%; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
