/* Momentum Tracker */
.momentum-panel { display: none; flex-direction: column; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 340px; max-height: 80vh; background: var(--bg-secondary, #1e1e1e); border: 1px solid var(--border-color, #333); border-radius: 12px; z-index: 10001; box-shadow: 0 8px 32px rgba(0,0,0,0.5); overflow: hidden; }
