.context-entity-tag { display: inline-block; font-size: 0.75rem; padding: 2px 8px; border-radius: 12px; margin: 2px 4px 2px 0; max-width: 100%; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.context-entity-tag.url { background: #1a3a5c; color: #6db3f8; text-decoration: none; }
.context-entity-tag.url:hover { background: #1e4a72; }
.context-entity-tag.lang { background: #2d1a4e; color: #b388ff; }
.context-entity-tag.file { background: #1a3c1a; color: #81c784; }
.context-entity-tag.num { background: #4e3a1a; color: #ffb74d; }
.context-entity-tag.term { background: #1a3a3c; color: #80cbc4; }
.context-related-msg { font-size: 0.8rem; padding: 8px; margin-bottom: 6px; background: var(--bg-tertiary, #252525); border-radius: 6px; cursor: pointer; color: var(--text-primary, #ccc); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; transition: background 0.2s; }
.context-related-msg:hover { background: var(--bg-hover, #333); }
.context-followup-btn { display: block; width: 100%; text-align: left; font-size: 0.8rem; padding: 8px 12px; margin-bottom: 6px; background: var(--bg-tertiary, #252525); border: 1px solid var(--border-color, #333); border-radius: 6px; color: var(--text-primary, #ddd); cursor: pointer; transition: all 0.2s; }
.context-followup-btn:hover { background: var(--accent-color, #2196F3); color: #fff; border-color: var(--accent-color, #2196F3); }
.context-empty { color: var(--text-secondary, #666); font-size: 0.8rem; font-style: italic; margin: 4px 0; }

/* Momentum Tracker */
.momentum-panel { display: none; flex-direction: column; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 340px; max-height: 80vh; background: var(--bg-secondary, #1e1e1e); border: 1px solid var(--border-color, #333); border-radius: 12px; z-index: 10001; box-shadow: 0 8px 32px rgba(0,0,0,0.5); overflow: hidden; }
.momentum-header { display: flex; justify-content: space-between; align-items: center; padding: 12px 16px; border-bottom: 1px solid var(--border-color, #333); }
.momentum-header h3 { margin: 0; font-size: 1rem; color: var(--text-primary, #eee); }
.momentum-body { padding: 16px; overflow-y: auto; display: flex; flex-direction: column; align-items: center; gap: 12px; }
.momentum-body canvas { display: block; }
.momentum-metric-row { display: flex; gap: 16px; justify-content: center; }
.momentum-metric { text-align: center; font-size: 0.85rem; color: var(--text-primary, #ddd); }
.momentum-metric strong { font-size: 1.2rem; color: var(--accent-color, #2196F3); }
.momentum-metric small { color: var(--text-secondary, #888); }
.momentum-alert { padding: 8px 12px; border-radius: 8px; font-size: 0.8rem; width: 100%; box-sizing: border-box; }
.momentum-alert.flow { background: rgba(255,152,0,0.15); color: #ff9800; border: 1px solid rgba(255,152,0,0.3); }
.momentum-alert.low { background: rgba(244,67,54,0.12); color: #f44336; border: 1px solid rgba(244,67,54,0.25); }
.momentum-alert.high { background: rgba(76,175,80,0.12); color: #4caf50; border: 1px solid rgba(76,175,80,0.25); }
.momentum-summary-grid { display: flex; gap: 20px; font-size: 0.8rem; color: var(--text-secondary, #aaa); }
.momentum-summary-grid strong { color: var(--text-primary, #ddd); }

